-- =============================================================================
-- 03_seed_stations.sql
-- Carga inicial del catálogo de estaciones (red pactada AdmiLogistic).
-- Origen: RAW_DATA + COORDS de public/gasolineras.html (160 estaciones).
-- Idempotente: ON CONFLICT DO NOTHING. Re-ejecutable sin duplicar.
--
-- NOTA lat/lng: las coordenadas provienen del diccionario COORDS del front
-- (precisión a nivel de localidad, no de surtidor). Son suficientes para el
-- mapa actual pero conviene geocodificar por dirección/ideess más adelante.
-- El campo station.ideess queda NULL: estas estaciones de la red pactada no
-- tienen código EESS de MINETUR asignado todavía.
-- =============================================================================

SET search_path TO gasoil, public;

-- 1) Tenant inicial: AdmiLogistic (uuid fijo y conocido para el seed)
VALUES ('00000000-0000-0000-0000-000000000001', 'AdmiLogistic', 'flota', 'pro')
ON CONFLICT (id) DO NOTHING;

