-- 3) Cache de precios inicial (producto 'gasoleo_a'), valor de RAW_DATA.
--    Esta tabla se PISA a diario desde MINETUR; aquí solo es semilla.
ON CONFLICT (station_id, producto) DO UPDATE
  SET precio = EXCLUDED.precio, actualizado_at = EXCLUDED.actualizado_at;

-- 4) Vínculo tenant_station: marca las 160 como pactadas para AdmiLogistic.
ON CONFLICT (tenant_id, station_id) DO NOTHING;
